blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>Pytania tak/nie</strong> – najprostszy typ pytań w języku angielskim, na który można odpowiedzieć „tak” lub „nie”.",
    "rules": [
        {
            "label": "Za pomocą DO/DOES/DID",
            "color": "emerald",
            "text": "<strong>Czasownik pomocniczy</strong> przed podmiotem:",
            "example": "Czy lubisz kawę? Czy ona tu pracuje?"
        },
        {
            "label": "Z TO BE",
            "color": "blue",
            "text": "<strong>Inwersja</strong> to czasownik przed podmiotem:",
            "example": "Jesteś gotowy? Czy jest nauczycielem?"
        },
        {
            "label": "Z MODAMI",
            "color": "amber",
            "text": "<strong>Czasownik modalny</strong> przed podmiotem:",
            "example": "Umiesz pływać? Czy powinniśmy iść?"
        }
    ]
}

{
    "title": "1. Co to są pytania ogólne?",
    "intro": "Tak/Nie Pytania (pytania ogólne) to pytania, na które możesz odpowiedzieć „tak” lub „nie”:",
    "items": [
        {
            "label": "Pytanie",
            "title": "Czy lubisz herbatę?",
            "subtitle": "Czy lubisz herbatę herbata?"
        },
        {
            "label": "Odpowiedź Tak, chcę. Ogólne pytania z DO/DOES/DID",
            "title": "Yes, I do.",
            "subtitle": "Так (подобається)."
        },
        {
            "label": "Відповідь "Ні"",
            "title": "No, I don't.",
            "subtitle": "Ні (не подобається)."
        }
    ]
}

{
    "title": "2. Загальні питання з DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple — DO/DOES",
            "color": "emerald",
            "description": "W czasie Present Simple używamy <strong>do</strong> (z ja, ty, my, oni) lub <strong>does</strong> (z on, ona, to).",
            "examples": [
                {
                    "en": "Czy mówisz po angielsku?",
                    "ua": "Czy mówisz po angielsku?"
                },
                {
                    "en": "Czy oni mieszkają w Kijowie?",
                    "ua": "Mieszkają w Kijowie?"
                },
                {
                    "en": "Czy ona tu pracuje?",
                    "ua": "Ona tu pracuje? działa?"
                },
                {
                    "en": "Does it work?",
                    "ua": "Це працює?"
                }
            ]
        },
        {
            "label": "Past Simple – DID",
            "color": "sky",
            "description": "W czasie Past Simple</strong> używamy słowa <strong>did</strong> w odniesieniu do wszystkich osób. Czasownik główny pozostaje w formie podstawowej.",
            "examples": [
                {
                    "en": "Czy widziałeś film?",
                    "ua": "Czy przybyli na czas?"
                },
                {
                    "en": "Did she call you?",
                    "ua": "Dzwoniła do ciebie?"
                },
                {
                    "en": " Wł. godzina?",
                    "ua": "Czy ona do ciebie dzwoniła?"
                },
                {
                    "en": "Czy wczoraj padał deszcz? ...?",
                    "ua": "Вчора йшов дощ?"
                }
            ]
        },
        {
            "label": "Структура",
            "color": "purple",
            "description": "Формула загального питання з do/does/did:",
            "examples": [
                {
                    "en": "Do/Does/Did + Subject + Verb (base form) + ...?",
                    "ua": "Pomocniczy + Podmiot + Czasownik + ...?"
                }
            ],
            "note": "📌 Czasownik główny występuje zawsze w formie podstawowej (bez -s, -ed)!"
        }
    ]
}

{
    "title": "3. Pytania ogólne z TO BE",
    "sections": [
        {
            "label": "Present Simple — AM/IS/ARE",
            "color": "blue",
            "description": "W przypadku czasownika <strong>to be</strong> w czasie Present Simple po prostu zmieniamy czasownik i podmiot.",
            "examples": [
                {
                    "en": "Czy jesteś gotowy?",
                    "ua": "Czy jesteś gotowy? gotowa?"
                },
                {
                    "en": "Czy ona jest nauczycielką?",
                    "ua": "Jest nauczycielką?"
                },
                {
                    "en": "Czy są w domu?",
                    "ua": "Są w domu?"
                },
                {
                    "en": "Czy to drogie?",
                    "ua": "Czy jest drogie?"
                }
            ]
        },
        {
            "label": "Past Simple — WAS/WERE",
            "color": "amber",
            "description": "W czasie przeszłym prostym używamy <strong>was</strong> (z ja, on, ona, to) lub <strong>were</strong> (z tobą, my, oni).",
            "examples": [
                {
                    "en": "Czy on był wczoraj w pracy?",
                    "ua": "Był wczoraj w pracy?"
                },
                {
                    "en": "Byłeś ty zmęczony?",
                    "ua": "Byłeś zmęczony?"
                },
                {
                    "en": "Czy byli szczęśliwi?",
                    "ua": "Byli szczęśliwi?"
                },
                {
                    "en": "Czy było to trudne?",
                    "ua": "Było trudne?"
                }
            ]
        },
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Ogólna formuła pytania z ma być:",
            "examples": [
                {
                    "en": "Jest/jest/jest/był/był + temat + ...?",
                    "ua": "forma ma być + temat + ...?"
                }
            ],
            "note": "📌 Nie ma potrzeby dodawania do/does/did z czasownikiem być!"
        }
    ]
}

{
    "title": "4. Ogólne pytania dotyczące czasowników modalnych pływać? ",
    "sections": [
        {
            "label": "CAN / COULD",
            "color": "emerald",
            "description": "З <strong>can/could</strong> (можу/міг би) ставимо модальне дієслово перед підметом.",
            "examples": [
                {
                    "en": "Can you swim?",
                    "ua": "Ти вмієш плавати?"
                },
                {
                    "en": "Umie prowadzić?",
                    "ua": "Umie prowadzić? przyjść?"
                },
                {
                    "en": "Could you help me?",
                    "ua": "Ти міг би мені допомогти?"
                },
                {
                    "en": "Could they come?",
                    "ua": "Вони змогли прийти?"
                }
            ]
        },
        {
            "label": "WILL / WOULD",
            "color": "sky",
            "description": "Za pomocą <strong>will/would</strong> (ja/would) również umieszczamy modal przed tematem.",
            "examples": [
                {
                    "en": "Przyjdziesz?",
                    "ua": "Ty przyjdź?"
                },
                {
                    "en": "Czy będzie padać?",
                    "ua": "Czy będzie padać?"
                },
                {
                    "en": "Chcesz kawę?",
                    "ua": "Powinieneś / MUSISZ / MAJ"
                },
                {
                    "en": "Would she agree?",
                    "ua": "Вона б погодилась?"
                }
            ]
        },
        {
            "label": "SHOULD / MUST / MAY",
            "color": "purple",
            "description": "Інші модальні дієслова працюють за тим самим принципом.",
            "examples": [
                {
                    "en": "Should we go?",
                    "ua": "Нам варто піти?"
                },
                {
                    "en": "Must I wait?",
                    "ua": "Я мушу чекати?"
                },
                {
                    "en": "May I ask?",
                    "ua": "Czy mogę zapytać?"
                }
            ],
            "note": "📌 Struktura: modalny + podmiot + czasownik (forma podstawowa) + ...?"
        }
    ]
}

{
    "title": "5. Pytania ogólne z HAVE GOT",
    "sections": [
        {
            "label": "HAVE GOT / HAS GOT",
            "color": "blue",
            "description": "Z <strong>have got</strong> (have) dokonujemy inwersji — przed podmiotem stawiamy have/has.",
            "examples": [
                {
                    "en": "Masz samochód?",
                    "ua": "Masz samochód? samochód?"
                },
                {
                    "en": "Czy ona ma psa? robi/robi.",
                    "ua": "У неї є собака?"
                },
                {
                    "en": "Have they got time?",
                    "ua": "У них є час?"
                }
            ]
        },
        {
            "label": "HAVE / HAS (володіння)",
            "color": "amber",
            "description": "У американському варіанті з <strong>have</strong> як основним дієсловом використовуємо do/does.",
            "examples": [
                {
                    "en": "Czy masz samochód?",
                    "ua": "Czy ona ma psa?"
                },
                {
                    "en": "Does she have a dog?",
                    "ua": "Czy oni mają czas?"
                },
                {
                    "en": "Do they have time?",
                    "ua": "Mają czas? Inne czasy"
                }
            ],
            "note": "📌 У британському варіанті частіше have got, у американському — have з do/does."
        }
    ]
}

{
    "title": "6. Інші часи",
    "sections": [
        {
            "label": "Present Continuous",
            "color": "emerald",
            "description": "Za pomocą <strong>Present Continuous</strong> (am/is/are + Ving) tworzymy inwersję am/is/are.",
            "examples": [
                {
                    "en": "Pracujesz teraz?",
                    "ua": "Pracujesz teraz?"
                },
                {
                    "en": "Czy ona nadchodzi?",
                    "ua": "Ona nadchodzi?"
                },
                {
                    "en": "Czy oni grają?",
                    "ua": "Grają?"
                }
            ]
        },
        {
            "label": "Present Perfect",
            "color": "sky",
            "description": "Za pomocą <strong>Present Perfect</strong> (have/has + V3) dokonujemy inwersji mieć/has.",
            "examples": [
                {
                    "en": "Czy widziałeś ten film?",
                    "ua": "Czy widziałeś ten film?"
                },
                {
                    "en": "Czy ona skończyli?",
                    "ua": "Czy skończyli?"
                },
                {
                    "en": "Przyszli? ona się uczy?",
                    "ua": "Вони приїхали?"
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "purple",
            "description": "З <strong>Past Continuous</strong> (was/were + Ving) робимо інверсію was/were.",
            "examples": [
                {
                    "en": "Were you sleeping?",
                    "ua": "Ти спав?"
                },
                {
                    "en": "Was she studying?",
                    "ua": "Uczyła się?[[(CODX_SEG_13]]]Czy oni oglądali telewizję? Tabela porównawcza"
                },
                {
                    "en": "Were they watching TV?",
                    "ua": "Вони дивилися телевізор?"
                }
            ],
            "note": "📌 Загальне правило: допоміжне дієслово виноситься перед підмет."
        }
    ]
}

{
    "title": "7. Порівняльна таблиця",
    "intro": "Jak tworzyć pytania ogólne z różnymi rodzajami czasowników:",
    "rows": [
        {
            "en": "Proste (zrobić/robi/zrobił)",
            "ua": "Czasy proste",
            "note": "Czy lubisz...? Czy ona działa...? Czy przyszli...?"
        },
        {
            "en": "Być (am/is/are/was/were)",
            "ua": "Czasownik do be",
            "note": "Czy jesteś gotowy? Czy ona tu jest? Czy byli szczęśliwi?"
        },
        {
            "en": "Modale (może/będzie/powinno...)",
            "ua": "Czasowniki modalne",
            "note": "Umiesz pływać? iść?"
        },
        {
            "en": "Masz",
            "ua": "Matkę (masz)",
            "note": "Masz...? Czy ona ma...?"
        },
        {
            "en": "Ciągła (jestem/jest/jestem + Ving)",
            "ua": "Ciągła razy",
            "note": "Pracujesz? Czy ona spała?"
        },
        {
            "en": "Idealnie (ma/ma + V3)",
            "ua": "Doskonałe czasy",
            "note": "Widziałeś… Czy ona skończyła…?"
        }
    ],
    "warning": "📌 Podstawowa zasada: <strong>czasownik pomocniczy przed podmiotem</strong>!"
}

{
    "title": "8. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Nieprawidłowa kolejność słów – podmiot przed czasownikiem.",
            "wrong": "❌ Jesteś gotowy? Umiesz pływać?",
            "right": " ✅ <span class="font-mono">Czy jesteś gotowy? Umiesz pływać?</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie „zrób/zrób” z „być”.",
            "wrong": "❌ Czy jesteś szczęśliwy? Byłeś tam?",
            "right": " ✅ <span class="font-mono">Czy jesteś zadowolony? Byłeś tam?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niepoprawna forma głównego czasownika.",
            "wrong": "❌ Czy ona pracuje? Czy poszli?",
            "right": "​​​​ <span class="font-mono">Czy ona pracuje? Czy poszli?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Pominięcie czasownika posiłkowego.",
            "wrong": "❌ Lubisz kawę? Ona tu pracuje?",
            "right": "​​​​ <span class="font-mono">Lubisz kawę? Czy ona tu pracuje?</span>"
        }
    ]
}

{
    "title": "10. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz poprawną formę pytania ogólnego.",
    "selects": [
        {
            "label": "a) Czy lubisz kawę? / b) Czy lubisz kawę? / c) Lubisz kawę?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Czy ona jest gotowa? / b) Czy jest gotowa? / c) Jest gotowa?",
            "prompt": "Która opcja jest prawidłowa?"
        },
        {
            "label": "a) Umiesz pływać? / b) Czy potrafisz pływać? / c) Umiesz pływać?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Poszli? / b) Czy poszli? / c) Poszli? zdanie.",
            "prompt": "Який варіант правильний?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Вправа 2. Постав питання",
    "input_intro": "Утвори загальне питання з поданого речення.",
    "inputs": [
        {
            "before": "Lubi herbatę. → ",
            "after": ""
        },
        {
            "before": "Są szczęśliwi. → ",
            "after": ""
        },
        {
            "before": "Umie tańczyć. → ",
            "after": ""
        },
        {
            "before": "Masz samochód. → ",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w pytaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Jesteś gotowy?",
            "example_target": "Czy jesteś gotowy gotowy?"
        },
        {
            "original": "1. Czy jest szczęśliwa?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Czy wrócili do domu?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Możesz mi pomóc?",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne tematy z działu Rodzaje zdań pytających",
    "items": [
        {
            "label": "Pytania tak/nie — pytania ogólne (bieżące)",
            "current": true
        },
        {
            "label": "Pytania Wh — pytania specjalne",
            "current": false
        },
        {
            "label": "Pytania tematyczne — pytania dotyczące tematu",
            "current": false
        },
        {
            "label": "Pytania alternatywne — pytania alternatywne",
            "current": false
        },
        {
            "label": "Tagi pytań — Pytania przekrojowe",
            "current": false
        }
    ]
}
